uniform float uRadius;
uniform float uSamples;
uniform float uBlurStrength;
uniform int uShapeType;
uniform vec2 uMouse;
uniform sampler2D uPreviousFrame;
uniform vec2 uResolution; // Ensure you have resolution for aspect ratio if needed

float gaussian(float x, float sigma) {
    // FIX 1: Prevent division by zero inside the exponent
    float s2 = 2.0 * sigma * sigma;
    if (s2 < 0.00001) return 1.0; // Return constant if sigma is basically zero
    return exp(-(x * x) / s2);
}

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {
    float dist = distance(uv, uMouse);

    // Smoothstep creates a softer transition to prevent hard math cutoffs
    // but we stick to your logic, just fixing the math errors.
    if (dist < uRadius) {
        outputColor = inputColor;
    } else {
        vec4 blurredColor = vec4(0.0);
        float totalWeight = 0.0;
        int samples = int(uSamples);

        // FIX 2: Clamp sigma so it never hits exactly 0.0
        // We use max(0.001, ...) to ensure it's always a valid number
        float sigma = max(0.001, uBlurStrength * (dist - uRadius)); 

        for (int i = 0; i < 50; ++i) { // GLSL loops often need fixed max iterations, using 50 as safety cap
            if (i >= samples) break;

            vec2 offset;
            if (uShapeType == 0) { // Circular blur
                float offsetAngle = float(i) / float(samples) * 6.28318; // 2*PI
                offset = vec2(cos(offsetAngle), sin(offsetAngle)) * sigma;
            } else if (uShapeType == 1) { // Horizontal blur
                offset = vec2(float(i) - float(samples) / 2.0, 0.0) / float(samples) * sigma * 2.0;
            } else { // Vertical blur
                offset = vec2(0.0, float(i) - float(samples) / 2.0) / float(samples) * sigma * 2.0;
            }

            vec2 sampleUv = uv + offset;
            float weight = gaussian(length(offset), sigma);

            blurredColor += texture2D(uPreviousFrame, sampleUv) * weight;
            totalWeight += weight;
        }

        // FIX 3: Safety check for totalWeight to prevent division by zero
        if (totalWeight > 0.001) {
            outputColor = blurredColor / totalWeight;
        } else {
            outputColor = inputColor;
        }
    }
}
